import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearch {

    private static final String LDAP_URL = "ldap://your_ldap_server_url";
    private static final String LDAP_USER = "your_ldap_username";
    private static final String LDAP_PASSWORD = "your_ldap_password";

    public Map<String, String> searchUserByUsername(String username) throws Exception {
        Context ctx = new InitialDirContext(new java.util.Hashtable<String, String>() {{
            put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            put(Context.PROVIDER_URL, LDAP_URL);
            put(Context.SECURITY_PRINCIPAL, LDAP_USER);
            put(Context.SECURITY_CREDENTIALS, LDAP_PASSWORD.toCharArray());
        }});

        SearchControls searchControls = new SearchControls();
        searchControls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        String[] attributes = {"mail", "cn", "department"};
        searchControls.setAttributes(attributes);

        String ldapQuery = "(uid=" + username + ")";
        NamingEnumeration<SearchResult> results = ctx.search("", ldapQuery, searchControls);

        Map<String, String> userAttributes = new HashMap<>();
        while (results.hasMoreElements()) {
            SearchResult result = results.next();
            Attributes attrs = result.getAttributes();

            userAttributes.put("email", (String) attrs.get("mail").get());
            userAttributes.put("fullName", (String) attrs.get("cn").get());
            userAttributes.put("department", (String) attrs.get("department").get());
        }

        ctx.close();
        return userAttributes;
    }
}